import{c as a,Q as r,j as t,m as p}from"./chunks/framework.hhGiamYR.js";const m=JSON.parse('{"title":"上路之前，你不需要知道终点——一个使节的行囊里装了什么","description":"","frontmatter":{"title":"上路之前，你不需要知道终点——一个使节的行囊里装了什么","date":"2026-06-05T00:00:00.000Z"},"headers":[],"relativePath":"research/travel-diplomacy/index.md","filePath":"research/travel-diplomacy/index.md"}'),o={name:"research/travel-diplomacy/index.md"};function l(n,e,i,s,h,c){return r(),t("div",null,[...e[0]||(e[0]=[p('<blockquote><p><em>来自佛罗伦萨的一封信</em></p></blockquote><p>有人问我：尼科洛，你半辈子都在出使——法国、德意志、罗马涅、乌尔比诺——你觉得旅行教会了你什么？</p><p>我想了想，回答是：<strong>旅行教会我的，不是关于远方的事，而是关于出发地的事。</strong></p><hr><h2 id="马背上的外交" tabindex="-1">马背上的外交 <a class="header-anchor" href="#马背上的外交" aria-label="Permalink to &quot;马背上的外交&quot;">​</a></h2><p>让我先告诉你一个事实：在十六世纪初的意大利，外交不是坐下来的事。外交是从马背上开始的。</p><p>从佛罗伦萨到里昂，两个星期的山路。从佛罗伦萨到因斯布鲁克——那是马克西米利安皇帝的宫廷——更要命，阿尔卑斯的隘口，冬天的泥浆没到马膝盖。你在这条路上不会学到任何谈判技巧。你会学到的是一件事：<strong>等待。</strong></p><p>等驿站的马换鞍。等渡口的船。等法国国王的心情。等等等等——而你口袋里只有每天 4 个弗罗林小金币的差旅费，连请驿站主人喝杯酒都要算计。</p><p>但我后来意识到，正是这些无用的等待，教会了我比任何书斋都多的东西。</p><hr><h2 id="布卢瓦-苍蝇与帝国" tabindex="-1">布卢瓦：苍蝇与帝国 <a class="header-anchor" href="#布卢瓦-苍蝇与帝国" aria-label="Permalink to &quot;布卢瓦：苍蝇与帝国&quot;">​</a></h2><p>1500 年，我 31 岁，第一次出使法国。</p><p>出发前，秘书厅的同僚们祝我好运。他们说，去向法国国王解释佛罗伦萨的立场——关于比萨，关于中立，关于我们在意大利的地位。他们给了我一份国书，我把它放在一个皮夹子里，贴身携带，好像那东西真能保护我。</p><p>到了布卢瓦城堡，我走进接见大厅的那一刻就知道：我不是来谈判的。我是来被忽略的。</p><blockquote><p>📖 <strong>盐野七生</strong>：《我的朋友马基雅维利》第八章</p><p>马基雅维利对此提出抗议，理由是这一点点钱完不成任务。他要求至少增加 4 弗罗林，同首席使节的经费一样。意见是要提的，但他很清楚必须尽快去向法国国王解释佛罗伦萨的立场。因而要求提了出来，人也出发去了法国。</p><p>—— <a href="https://niflhum.top/machiavelli-library/library/biography/salt-seven/08-%E7%AC%AC%E5%85%AB%E7%AB%A0.md" target="_blank" rel="noreferrer">阅读原文</a></p></blockquote><p>路易十二坐在高台上，没有站起来。我开口说了佛罗伦萨的立场。他点了点头，然后问：&quot;那边天气怎么样了？&quot;</p><p>这不是对天气的关心。这是一个帝国对一个城邦的定位：你们提供不了任何军事价值，唯一值得问的是你们那边是晴天还是雨天。</p><p>从布卢瓦骑马回佛罗伦萨要两个星期。那十四天里，我一直在想一句话：你不是外交官。你是一个替苍蝇说话的人。法国国王刚才用一句关于天气的话，证明了他连这只苍蝇都懒得拍。</p><hr><h2 id="从外面看自己" tabindex="-1">从外面看自己 <a class="header-anchor" href="#从外面看自己" aria-label="Permalink to &quot;从外面看自己&quot;">​</a></h2><p>这不是自怜。这是我这辈子上的最重要的一课。</p><p>你在佛罗伦萨的时候，身边全是佛罗伦萨人。他们讨论执政团、讨论美第奇、讨论比萨，每一个议题都像是宇宙的中心。你走出去，走到布卢瓦——你突然发现，法国国王在乎的不是比萨，不是执政团，甚至不是意大利，而是那不勒斯王国的继承权。</p><p>你花十四年生长的世界，在别人眼里只是一个临时注脚。</p><blockquote><p>📖 <strong>《君主论》</strong> 第三章</p><p>&quot;路易十二犯下了五个错误：他消灭了弱小的势力；他在意大利助长了一个强权的势力；他引入了一个极为强大的外邦人；他没有亲自驻跸在那里；他没有向那里殖民。&quot;</p><p>—— <a href="https://niflhum.top/machiavelli-library/library/machiavelli/prince/en/III-chapter.md" target="_blank" rel="noreferrer">阅读原文</a></p></blockquote><p>你读这段话，可能会觉得这是一个政治家的冷静分析。但我要告诉你：这段话的每一个字，都是在布卢瓦的大厅里闻着松脂和旧石头的气味写出来的。五年出使的代价换来的不是金钱——是一双能从外面看自己的眼睛。</p><hr><h2 id="旅行不是看风景" tabindex="-1">旅行不是看风景 <a class="header-anchor" href="#旅行不是看风景" aria-label="Permalink to &quot;旅行不是看风景&quot;">​</a></h2><p>后来我出使过切萨雷·博尔贾的营帐，去过马克西米利安的宫廷，来回穿越亚平宁山脉的次数多到数不清。每一次上路，我都带着同一件东西——不是国书，不是金币，是一本李维的《罗马史》，塞在马鞍袋里。</p><p>白天，看切萨雷怎么处置叛将。晚上，在李维的书里读罗马人怎么处置同样的事。白天和晚上之间，路程在走，想法在长。</p><p>这就是旅行的真正价值。不是目的地的谈判桌。是你从谈判桌走回驿站的路上，脑中翻涌的那些东西。是你在法国国王轻蔑的目光下压住怒火的那几秒钟，训练出来的观察力。</p><p>十四年的使节生涯教会我一件事：<strong>你不出发，你永远不会知道你是小的。你不知道自己是小的，你就永远也大不起来。</strong></p><hr><p><em>读万卷书，走万里路。书告诉你世界应该怎样，路告诉你世界实际上是怎样。</em></p><p>尼科洛·马基雅维利<br> 圣卡夏诺，乡间书房</p>',34)])])}const u=a(o,[["render",l]]);export{m as __pageData,u as default};
